fn takes(v: Vec<i32>) {
    println!("{}", v.len());
} // v is dropped here

fn main() {
    let s1 = String::from("hello");
    let s2 = s1;            // ownership moves to s2
    // println!("{}", s1);  // error: s1 was moved
    println!("{s2}");

    let data = vec![1, 2, 3];
    takes(data);            // data moved into function
}

fn main() {
    let mut v = vec![1, 2, 3];
    let first = &v[0];      // immutable borrow
    // v.push(4);           // error: cannot mutate while borrowed
    println!("{first}");    // borrow ends after last use (NLL)
    v.push(4);              // now allowed
    println!("{v:?}");
}

fn longest<'a>(x: &'a str, y: &'a str) -> &'a str {
    if x.len() > y.len() { x } else { y }
}

fn main() {
    let s1 = String::from("long");
    let s2 = String::from("longer");
    let result = longest(&s1, &s2);
    println!("{result}");
}

#[derive(Copy, Clone)]
struct Point { x: i32, y: i32 }

fn main() {
    let p = Point { x: 1, y: 2 };
    let q = p;          // copied, p still valid
    println!("{} {}", p.x, q.x);

    let s = String::from("hi");
    let t = s.clone();  // explicit deep copy (String is not Copy)
    println!("{s} {t}");
}

fn sum(nums: &[i32]) -> i32 { nums.iter().sum() }
fn greet(name: &str) -> String { format!("Hi, {name}") }

fn main() {
    let v = vec![1, 2, 3, 4, 5];
    println!("{}", sum(&v[1..3]));    // sub-slice: 2 + 3
    let owned = String::from("world");
    println!("{}", greet(&owned));    // String derefs to &str
}

fn find(v: &[i32], target: i32) -> Option<usize> {
    v.iter().position(|&x| x == target)
}

fn parse(s: &str) -> Result<i32, std::num::ParseIntError> {
    s.parse::<i32>()
}

fn main() {
    println!("{:?}", find(&[1, 2, 3], 2)); // Some(1)
    println!("{:?}", parse("42"));         // Ok(42)
}

use std::num::ParseIntError;

fn double(s: &str) -> Result<i32, ParseIntError> {
    let n = s.parse::<i32>()?; // returns Err early on failure
    Ok(n * 2)
}

fn main() {
    println!("{:?}", double("21"));  // Ok(42)
    println!("{:?}", double("x"));   // Err(ParseIntError)
}

enum Shape { Circle(f64), Rect(f64, f64) }

fn area(s: &Shape) -> f64 {
    match s {
        Shape::Circle(r) => std::f64::consts::PI * r * r,
        Shape::Rect(w, h) => w * h,
    }
}

fn main() {
