use std::fmt::Display;

fn largest<T: PartialOrd + Copy>(list: &[T]) -> T {
    let mut max = list[0];
    for &item in list {
        if item > max { max = item; }
    }
    max
}

fn print_all<T: Display>(items: &[T]) {
    for i in items { println!("{i}"); }
}

fn main() {
    let nums = vec![1, 2, 3, 4, 5];
    let factor = 10;
    let result: Vec<i32> = nums
        .iter()
        .filter(|&&x| x % 2 == 0)
        .map(|&x| x * factor) // Fn closure captures factor
        .collect();
    println!("{result:?}"); // [20, 40]

    let mut count = 0;
    let mut inc = || count += 1; // FnMut: mutates capture
    inc(); inc();
    println!("{count}"); // 2
}

use std::rc::Rc;
use std::sync::Arc;

fn main() {
    let boxed = Box::new(42);          // heap-owned
    let shared = Rc::new(vec![1, 2]);
    let clone = Rc::clone(&shared);    // count = 2
    println!("{}", Rc::strong_count(&shared));

    let a = Arc::new(String::from("threadsafe"));
    let b = Arc::clone(&a);            // safe across threads
    println!("{} {} {}", boxed, a, b);
}

use std::cell::RefCell;
use std::rc::Rc;

fn main() {
    let shared = Rc::new(RefCell::new(0));
    let clone = Rc::clone(&shared);
    *shared.borrow_mut() += 5;   // mutate through shared ref
    *clone.borrow_mut() += 3;
    println!("{}", shared.borrow()); // 8
}

use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let counter = Arc::new(Mutex::new(0));
    let mut handles = vec![];
    for _ in 0..5 {
        let c = Arc::clone(&counter);
        handles.push(thread::spawn(move || {
            *c.lock().unwrap() += 1;
        }));
    }
    for h in handles { h.join().unwrap(); }
    println!("{}", *counter.lock().unwrap()); // 5
}

use tokio::time::{sleep, Duration};

async fn fetch(id: u32) -> u32 {
    sleep(Duration::from_millis(10)).await;
    id * 2
}

#[tokio::main]
async fn main() {
    let (a, b) = tokio::join!(fetch(1), fetch(2));
    println!("{a} {b}"); // 2 4
}

macro_rules! max {
    ($a:expr, $b:expr) => {
        if $a > $b { $a } else { $b }
    };
}

fn main() {
    println!("{}", max!(3, 7)); // 7
    let v = vec![1, 2, 3];      // vec! is a macro too
    println!("{v:?}");
}

fn main() {
    let mut num = 5;
    let r1 = &num as *const i32;      // raw pointer
    let r2 = &mut num as *mut i32;
    unsafe {
        println!("{}", *r1);          // deref raw pointer
        *r2 = 10;
    }
    println!("{num}"); // 10
}

