fn main() {
    // High-level iterator chain...
    let sum: u32 = (1..=1000)
        .filter(|n| n % 3 == 0)
        .sum();
    // ...compiles to a loop as fast as a manual one
    println!("{sum}");

    // Option<&T> is the same size as &T (null-pointer optimization)
    assert_eq!(
        std::mem::size_of::<Option<&u8>>(),
        std::mem::size_of::<&u8>()
    );
}
